      cb.runAsJob('pipeline', _pLabel, withThreadOutcome(_pCwd, 'pipeline', _pLabel, () => handlePipeline(intent.task, cb.dispatch, cb.ctx, intent.fitnessCmd ?? undefined), cb.ctx));
